Here's how to test `DataFetcher` with MSTest, covering success, failure, timeout, and cancellation:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    [TestMethod]
    public async Task FetchAsync_SuccessResponse_ReturnsContent()
    {
        // Arrange
        var handler = new FakeHandler("hello");
        var client = new HttpClient(handler) { BaseAddress = new Uri("https://example.com") };
        var fetcher = new DataFetcher(client);

        // Act
        var result = await fetcher.FetchAsync("https://example.com/data");

        // Assert
        Assert.AreEqual("hello", result);
    }

    [TestMethod]
    public async Task FetchAsync_ErrorResponse_ThrowsHttpRequestException()
    {
        var handler = new FakeHandler(HttpStatusCode.InternalServerError);
        var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await fetcher.FetchAsync("https://example.com/fail"));
    }

    [TestMethod]
    [Timeout(5000)] // MSTest cancels via TestContext.CancellationToken after 5s
    public async Task FetchAsync_WithTimeout_CompletesBeforeDeadline()
    {
        var handler = new FakeHandler("fast");
        var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        // Pass TestContext.CancellationToken so the timeout is cooperative
        var result = await fetcher.FetchAsync(
            "https://example.com/data", _testContext.CancellationToken);

        Assert.AreEqual("fast", result);
    }

    [TestMethod]
    public async Task FetchAsync_WhenCancelled_ThrowsOperationCanceled()
    {
        var cts = new CancellationTokenSource();
        var handler = new FakeHandler(delay: TimeSpan.FromSeconds(30));
        var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        cts.Cancel(); // cancel immediately

        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com/slow", cts.Token));
    }
}
```

And a minimal `FakeHandler` to avoid real HTTP calls:

```csharp
file sealed class FakeHandler : HttpMessageHandler
{
    private readonly HttpStatusCode _status;
    private readonly string _content;
    private readonly TimeSpan _delay;

    public FakeHandler(string content, HttpStatusCode status = HttpStatusCode.OK)
    {
        _content = content;
        _status = status;
    }

    public FakeHandler(HttpStatusCode status) : this(string.Empty, status) { }

    public FakeHandler(TimeSpan delay) : this(string.Empty)
    {
        _delay = delay;
    }

    protected override async Task<HttpResponseMessage> SendAsync(
        HttpRequestMessage request, CancellationToken cancellationToken)
    {
        if (_delay > TimeSpan.Zero)
            await Task.Delay(_delay, cancellationToken);

        return new HttpResponseMessage(_status)
        {
            Content = new StringContent(_content),
        };
    }
}
```

**Key points:**

- **`[Timeout(5000)]`** + **`_testContext.CancellationToken`** — MSTest fires that token when the timeout elapses, but only if your code passes it through. Always thread it into async calls.
- **`Assert.ThrowsExactlyAsync<T>`** — preferred over `[ExpectedException]`; lets you inspect the exception and keeps assertions explicit.
- **`FakeHandler`** — subclass `HttpMessageHandler` instead of mocking `HttpClient` directly; it's the standard seam for testing HTTP code.
- **Sealed test class** and **constructor-injected `TestContext`** — both MSTest 3.x+ best practices.
